import{_ as i,H as s,f as l,i as t}from"./chunks/framework.Cvt1eIE0.js";const p="/assets/libclang.DMClnFXL.png",d="/assets/mvn-libclang.C_DdXngD.png",e="/assets/visual-studio-cli.Cwf_hLAx.png",c="/assets/finished.DhCg487k.png",v=JSON.parse('{"title":"本项目的构建方法","description":"","frontmatter":{},"headers":[],"relativePath":"getstart/abstract.md","filePath":"getstart/abstract.md"}'),n={name:"getstart/abstract.md"};function o(r,a,h,k,g,u){return s(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="本项目的构建方法" tabindex="-1">本项目的构建方法 <a class="header-anchor" href="#本项目的构建方法" aria-label="Permalink to &quot;本项目的构建方法&quot;">​</a></h1><p>本项目目前主要包含以下几个部分：</p><ol><li>libclang基础项目</li><li>Layered Header Parser</li><li>Layered Java Runtime</li><li>Layered Maven plugin</li></ol><p>想要构建本项目，需要安装<code>Microsoft Visual Studio</code>，并且只少包含<code>C/C++</code>组件， <code>CMake</code>工具，<code>Java 11+</code>，<code>Maven</code>，并且务必将<code>Maven</code>和<code>CMake</code>以及<code>Java</code>配置到环境变量<code>PATH</code> 以便于接下来在命令行中访问。</p><ul><li>Maven可以在这里找到：<a href="https://maven.apache.org/download.cgi" target="_blank" rel="noreferrer">https://maven.apache.org/download.cgi</a></li><li>CMake可以在这里找到：<a href="https://cmake.org/" target="_blank" rel="noreferrer">https://cmake.org/</a></li><li>Java可以在这里找到： <a href="https://adoptium.net/zh-CN" target="_blank" rel="noreferrer">https://adoptium.net/zh-CN</a></li><li>vcpkg可以在这里找到：<a href="https://github.com/Microsoft/vcpkg" target="_blank" rel="noreferrer">https://github.com/Microsoft/vcpkg</a></li><li>libclang和llvm可以在这里找到：<a href="https://github.com/llvm/llvm-project/releases" target="_blank" rel="noreferrer">https://github.com/llvm/llvm-project/releases</a></li><li>Visual studio，这个就不贴了，自己去翻微软官网。</li></ul><h2 id="libclang基础项目" tabindex="-1">libclang基础项目 <a class="header-anchor" href="#libclang基础项目" aria-label="Permalink to &quot;libclang基础项目&quot;">​</a></h2><p>这个项目目前是我的cpp-presets项目的一部分，应该有编译好的包可以直接使用，也可也通过github拉取该项目 并且编译和安装到本地Maven中（推荐）。</p><p>请首先从GitHub获取cpp-presets项目，并且解压或者clone到硬盘合适的位置，接下来， 导航至cpp-presets项目的根目录，使用你的IDE打开该项目，找到它的<code>libclang</code>子项目的<code>pom.xml</code>并且 进行如下修改：</p><p>下载一份clang编译器，大小大概1G上下，里面可以找到libclang.lib（位于解压后的libs目录） 和libclang.dll（位于解压后的bin目录），把它们复制到<code>cpp-presets</code>项目的<code>platform/libclang/dll/windows/x86_64</code> 目录中：</p><p><img src="'+p+'" alt="lib-clang"></p><p>接下来将下图标出的<code>build.skip</code>配置修改为false，这样Maven将会通过<code>JavaCpp</code>生成<code>libclang</code>的JNI wrapper。</p><p><img src="'+d+'" alt="libclang-pom"></p><p>完成修改后，打开开始菜单，在里面找到Visual studio的目录，里面有<code>Visual studio x64 native tools</code>命令行， 你应该可以在开始菜单的Visual studio目录中找到它：</p><p><img src="'+e+'" alt="VisualStudioCli"></p><p>打开后，在命令行窗口导航到存放<code>cpp-presets</code>的目录，执行下面的指令来进行编译：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libclang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span></span></code></pre></div><p>你会在<code>libclang.main</code>这个位置看到很多编译产物，请把生成的dll移动到<code>libclang</code>项目合适的位置， 也就是<code>resource/org/swdc/libclang/core/windows-x86_64</code>这里面，此外，<code>libclang.dll</code> 也需要放进去，整理完毕的项目如下图：</p><p><img src="'+c+`" alt="compiled"></p><p>接下来将<code>build.skip</code>配置修改为true，删除dll之外其他的编译产物，并且执行以下指令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libclang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libclang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libclang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>那么到这里libclang的Java wrapper就准备完毕了。</p><h2 id="layered-java运行时库" tabindex="-1">Layered Java运行时库 <a class="header-anchor" href="#layered-java运行时库" aria-label="Permalink to &quot;Layered Java运行时库&quot;">​</a></h2><p>这个项目展示了Java是如何使用头文件解析器生成的CMake项目的，这些胶水代码已经将各种API的接口进行了 规范，并且提供了必要的元数据，通过这些就能借助libffi项目实现Java对外部函数的调用，该项目目前在进行 可用性的验证。</p><p>本项目也分为native（C/C++）和Java的两个部分，native部分主要提供了内存操作以及<code>libffi</code>的外部函数调用 能力，而Java部分则是对native的操作封装，Java的部分不需要特别的处理，关键在于它的本地库。</p><p>这个项目使用<code>vcpkg</code>，所以你需要首先下载一份<code>vcpkg</code>的release包，并且解压到<code>layered-runtime/native/vcpkg</code>目录里面， 本项目不会把<code>vcpkg</code>打包在内，不然体积就太大了。</p><p>在继续之前，你需要再有管理员权限的<code>Windows PowerShell</code>命令行中执行以下指令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Set-ExecutionPolicy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ExecutionPolicy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> RemoteSigned</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Scope</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CurrentUser</span></span></code></pre></div><p>它的目的是允许Power shell执行脚本，本项目需要这项权限来使用vcpkg。</p><p>同样的，你需要使用Visual studio的cli环境启动本项目的编译，在开始菜单找到Visual studio，里面有<code>Visual studio x64 native tools</code>命令行， 你应该可以在开始菜单的Visual studio目录中找到它：</p><p><img src="`+e+`" alt="VisualStudioCli"></p><p>在这个命令行中，你需要导航到<code>layered-runtime</code>的<code>native</code>目录，并且执行以下指令启动编译：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>此时在build目录下应该已经生成了Visual studio的Project（<code>.sln</code>），打开它吧，通过Visual studio应该可以 正确的生成所需的二进制库，顺便，如果cmake执行过程遇到了问题，那么很可能是网络导致的，多试几次总会成功。</p><p>如果你使用的是<code>Debug</code>模式，那么你可以在build目录的<code>Debug</code>子目录找到生成的动态库，如果是<code>Release</code>模式，你可以 在<code>Release</code>子目录找到它，这里面所有的动态库都是本项目需要的，需要把它们复制到resource目录的以下位置：</p><p><code>org/swdc/layered/module/windows-x86_64</code></p><p>接下来你可以对本项目指向Maven的install指令，Layered Java运行时库就准备完毕了。</p><h2 id="layered-头文件解析器" tabindex="-1">Layered 头文件解析器 <a class="header-anchor" href="#layered-头文件解析器" aria-label="Permalink to &quot;Layered 头文件解析器&quot;">​</a></h2><p>这个项目是基于libclang实现的C语言Header解析工具，主要的目的是解析头文件<code>*.h</code>并且从中提取元数据， 生成胶水代码和CMake项目，目前正在验证对于C语言的可用性，它复用了一部分Layered Java运行时库的组件， 所以构建本项目之前需要首先构建这个Layered Java运行时库。</p>`,38)])])}const F=i(n,[["render",o]]);export{v as __pageData,F as default};
